    class UnionFind {
        parent: number[];
        rank: number[];
        constructor(n: number) {
            this.parent = Array.from({ length: n }, (_, i) => i);
            this.rank = Array(n).fill(0);
        }
        find(x: number): number {
            if (this.parent[x] !== x) {
                this.parent[x] = this.find(this.parent[x]);
            }
            return this.parent[x];
        }
        union(x: number, y: number): boolean {
            const xRoot = this.find(x);
            const yRoot = this.find(y);
            if (xRoot === yRoot) return false;
            if (this.rank[xRoot] < this.rank[yRoot]) {
                this.parent[xRoot] = yRoot;
            } else {
                this.parent[yRoot] = xRoot;
                if (this.rank[xRoot] === this.rank[yRoot]) {
                    this.rank[xRoot]++;
                }
            }
            return true;
        }
    }

    // Initialize Union-Find
    const uf = new UnionFind(n);

    // Track the maximum edge weight in each component
    const maxEdgeInComponent: number[] = Array(n).fill(0);

    // Process edges in increasing order of weight
    let result = 0;
    let components = n;

    for (const [u, v, w] of edges) {
        const rootU = uf.find(u);
        const rootV = uf.find(v);

        if (rootU !== rootV) {
            // Merge the components
            uf.union(rootU, rootV);

            // Update the maximum edge weight in the new component
            const newMax = Math.max(maxEdgeInComponent[rootU], maxEdgeInComponent[rootV], w);
            maxEdgeInComponent[rootU] = newMax;

            // Decrease the number of components
            components--;

            // If we have reached the desired number of components, return the maximum edge weight
            if (components === k) {
                return newMax;
            }
        }
    }

    // If we haven't returned yet, the maximum edge weight is the maximum in the entire graph
    return Math.max(...maxEdgeInComponent);
